"use strict";(self.webpackChunkcatalog_docs=self.webpackChunkcatalog_docs||[]).push([[53],{1109:a=>{a.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Introduction","href":"/","docId":"intro"},{"type":"category","label":"Catalog Accounts","collapsible":true,"collapsed":false,"items":[{"type":"link","label":"Introduction","href":"/catalog-accounts/introduction","docId":"catalog-accounts/introduction"},{"type":"link","label":"Instant Account","href":"/catalog-accounts/instant-account","docId":"catalog-accounts/instant-account"},{"type":"link","label":"Guardian","href":"/catalog-accounts/guardian","docId":"catalog-accounts/guardian"},{"type":"link","label":"API","href":"/catalog-accounts/api","docId":"catalog-accounts/api"}]},{"type":"category","label":"Catalog Swaps","collapsible":true,"collapsed":false,"items":[{"type":"link","label":"Introduction","href":"/catalog-swaps/introduction","docId":"catalog-swaps/introduction"},{"type":"link","label":"HTLCs","href":"/catalog-swaps/htlcs","docId":"catalog-swaps/htlcs"},{"type":"link","label":"Order Book","href":"/catalog-swaps/order-book","docId":"catalog-swaps/order-book"},{"type":"link","label":"Multi-CoW","href":"/catalog-swaps/multi-cow","docId":"catalog-swaps/multi-cow"},{"type":"link","label":"Batch Auctions","href":"/catalog-swaps/batch-auctions","docId":"catalog-swaps/batch-auctions"},{"type":"link","label":"COBI","href":"/catalog-swaps/cobi","docId":"catalog-swaps/cobi"},{"type":"link","label":"API","href":"/catalog-swaps/api","docId":"catalog-swaps/api"}]},{"type":"link","label":"Catalog Wallet","href":"/catalog-wallet","docId":"catalog-wallet"},{"type":"link","label":"Audits","href":"/audits","docId":"audits"}]},"docs":{"audits":{"id":"audits","title":"Audits","description":"Completed audits are available below. Audits are a continuous process, and this list will continue to be updated as more audits are completed.","sidebar":"tutorialSidebar"},"catalog-accounts/api":{"id":"catalog-accounts/api","title":"API","description":"Description","sidebar":"tutorialSidebar"},"catalog-accounts/guardian":{"id":"catalog-accounts/guardian","title":"Guardian","description":"The Guardian is a co-signing service for the Instant Account. The Guardian ensures secure transactions by eliminating the possibility of double spending without the need for confirmation delays. It achieves this by providing a second signature for all account operations, meaning it can guarantee no operation will be able to override existing ones. The Guardian does not require any trust from the user as it signs a refund transaction prior to any funding request, meaning the user can withdraw at any point in the event the Guardian becomes unresponsive.","sidebar":"tutorialSidebar"},"catalog-accounts/instant-account":{"id":"catalog-accounts/instant-account","title":"Instant Account","description":"All Catalog Accounts come with the ability to open an Instant Account. An Instant Account is a special type of wallet which enables instant transfers and cross-chain swaps, without requiring any form of trust. It does this through a 2-of-2 multi-sig requirement with the Guardian component, which allows users to bypass confirmation delays.","sidebar":"tutorialSidebar"},"catalog-accounts/introduction":{"id":"catalog-accounts/introduction","title":"Introduction","description":"Catalog Accounts support the way you interact with Web3. These are non-custodial accounts that allow you to store assets from any blockchain, and use them without waiting for confirmation delays.","sidebar":"tutorialSidebar"},"catalog-swaps/api":{"id":"catalog-swaps/api","title":"API","description":"Description","sidebar":"tutorialSidebar"},"catalog-swaps/batch-auctions":{"id":"catalog-swaps/batch-auctions","title":"Batch Auctions","description":"Work in progress.","sidebar":"tutorialSidebar"},"catalog-swaps/cobi":{"id":"catalog-swaps/cobi","title":"COBI","description":"Work in progress.","sidebar":"tutorialSidebar"},"catalog-swaps/htlcs":{"id":"catalog-swaps/htlcs","title":"HTLCs","description":"Catalog Swaps use hashed timelock contracts (HTLCs) for execution, which function as a two-way virtual safe.","sidebar":"tutorialSidebar"},"catalog-swaps/introduction":{"id":"catalog-swaps/introduction","title":"Introduction","description":"Catalog Swaps offer you a way to execute cross-chain swaps instantly and seamlessly. Multiple resolvers compete in an auction format to provide the best possible rate for the user, allowing gas payments in any token. Atomic execution for Catalog Swaps is guaranteed through the use of HTLCs.","sidebar":"tutorialSidebar"},"catalog-swaps/multi-cow":{"id":"catalog-swaps/multi-cow","title":"Multi-CoW","description":"Coincidence of Wants (CoW) is a model designed by CoW Protocol, which provides an off-chain optimisation to the traditional on-chain market making system. CoW enables users that hold an asset that the other wants to exchange assets directly, without the need for an external market maker or liquidity provider. This model makes perfect sense for Catalog\'s order book where each swap contains a common denominating cross-chain component which must be accommodated for.","sidebar":"tutorialSidebar"},"catalog-swaps/order-book":{"id":"catalog-swaps/order-book","title":"Order Book","description":"Catalog uses a CLOB (central limit order book) to offer users a way to execute swaps without spending gas or risking being front-run. All orders are filled by a third-party resolver, which is a professional market maker who pays applicable gas fees, while profiting from arbitrage trading.","sidebar":"tutorialSidebar"},"catalog-wallet":{"id":"catalog-wallet","title":"Catalog Wallet","description":"Catalog Wallet is a browser extension that enables seamless support for cross-chain assets on all dApps, meaning you can transact Bitcoin and other assets directly on your favorite exchange or NFT marketplace. Catalog Wallet uses Catalog Accounts under the hood, abstracting away all of the powerful technology that make your multichain experience possible.","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction","description":"What is Catalog?","sidebar":"tutorialSidebar"}}}')}}]);